INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('cba14476c81a2838', 'AR', '["federal","state","county"]', 'ballot_access', 'Does Arkansas have an open or closed primary system?', '["Arkansas primary voting rules","Do I have to register with a party to vote in the AR primary?","Can unaffiliated voters participate in the Arkansas primary?"]', 'Arkansas operates a partially open primary system. Voters do not register by political party in advance and may select whichever party''s ballot they wish to vote on at the polls. However, the Republican Party of Arkansas recently instituted a rule closing their primary to individuals explicitly registered as Democrats, though unaffiliated and optional voters can still choose either ballot.', 'https://www.sos.arkansas.gov/elections/voter-information', 'Arkansas Secretary of State - Voter Information', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('44585f534d01c2d4', 'AR', '["federal","state","county"]', 'election_dates', 'When is the 2026 primary election in Arkansas?', '["Arkansas primary date 2026","When is Election Day for the AR primary?","March primary Arkansas"]', 'Following a recent law that moved nonpresidential primaries from May to March, the Arkansas Preferential Primary Election will be held on Tuesday, March 3, 2026. This makes it one of the earliest primaries in the nation.', 'https://www.sos.arkansas.gov/uploads/elections/2026_Election_Calendar_Rev._6-2025_.pdf', 'Arkansas Secretary of State - 2026 Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('3eaa8e38d990a18d', 'AR', '["federal","state","county"]', 'runoff_rules', 'When are primary runoffs held in Arkansas?', '["Arkansas primary runoff date 2026","What is the threshold to avoid a runoff in AR?","50 percent plus one rule Arkansas primary"]', 'In Arkansas, a candidate must secure a strict majority (50% plus one vote) to win a primary election outright. If no candidate reaches this threshold, the top two candidates advance to a General Primary Election (Runoff). For the 2026 cycle, the primary runoff is scheduled for Tuesday, March 31, 2026.', 'https://www.sos.arkansas.gov/uploads/elections/2026_Election_Calendar_Rev._6-2025_.pdf', 'Arkansas Secretary of State - 2026 Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('3137af12b33db795', 'AR', '["county","municipal"]', 'runoff_rules', 'Does Arkansas have runoff elections for the general election?', '["Arkansas general election runoff rules","Do state candidates face a general runoff in AR?","December 1 runoff Arkansas"]', 'Yes, but strictly limited by office level. Under Arkansas Code § 7-5-106, general election runoffs (scheduled for December 1, 2026) apply ONLY to county and municipal offices where no candidate receives a required threshold (majority or 40% plus 20% margin). State and federal candidates are elected by a simple plurality in the general election and DO NOT face general election runoffs.', 'https://codes.findlaw.com/ar/title-7-elections/ar-code-sect-7-5-106/', 'Arkansas Code § 7-5-106', '2026-05-17', 'static', 'statute_citation', 'Local candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('4aac0422fbba22c7', 'AR', '["federal","state","county","municipal"]', 'ballot_access', 'Are write-in candidates permitted in Arkansas?', '["Do write-in votes count in AR?","How to register as a write-in candidate in Arkansas","SB 254 write-in ban Arkansas"]', 'No. In a major and highly distinctive policy shift, the Arkansas legislature passed SB 254 in 2023, which completely eliminated the write-in candidate portion on all ballots. Write-in candidacies and write-in votes are no longer permitted or counted in any Arkansas election.', 'https://arkansashouse.org/news/post/20206/week-10-of-the-2023-regular-session', 'Arkansas House of Representatives - 2023 Enactments', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('65b75c776886812c', 'AR', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for major party candidates in Arkansas for 2026?', '["When do candidates file for office in Arkansas?","Arkansas filing week dates 2026","November filing deadline AR"]', 'Because Arkansas moved its primary to March, the filing period for major party candidates is extraordinarily early. Under Arkansas Code § 7-7-203(c)(1), the one-week party filing period begins at 12:00 noon on the first Monday in November preceding the primary. For the 2026 cycle, candidates must file in early November 2025.', 'https://codes.findlaw.com/ar/title-7-elections/ar-code-sect-7-7-203/', 'Arkansas Code § 7-7-203', '2026-05-17', 'per_cycle', 'statute_citation', 'Major party candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('cb2eee7cd8113b14', 'AR', '["federal","state","county"]', 'ballot_access', 'What is the filing deadline for independent candidates in Arkansas?', '["Independent candidate petition deadline Arkansas","Running without a party in AR 2026","May 1 independent deadline Arkansas"]', 'Independent candidates who wish to appear on the general election ballot must file a political practices pledge, affidavit of eligibility, and a petition containing the required number of verified registered voter signatures by 12:00 noon on May 1 of the election year (May 1, 2026).', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'Independent candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('8a0a62626986e010', 'AR', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Arkansas?', '["Arkansas joint ticket rules","How are Lt Gov candidates selected in AR?","Does the Governor pick a running mate in Arkansas?"]', 'No. In Arkansas, the Governor and Lieutenant Governor are elected completely separately. They run in separate primaries and appear as separate items on the general election ballot, meaning it is possible for voters to elect a Governor and Lieutenant Governor from two different political parties.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('3ecde9a1b83349ed', 'AR', '["federal","state","county"]', 'election_dates', 'When is the general election in Arkansas for 2026?', '["Arkansas general election date 2026","When is Election Day 2026 in Arkansas?","November election Arkansas"]', 'The Arkansas general election will be held on Tuesday, November 3, 2026. Polls are open statewide from 7:30 a.m. to 7:30 p.m. local time.', 'https://www.sos.arkansas.gov/uploads/elections/2026_Election_Calendar_Rev._6-2025_.pdf', 'Arkansas Secretary of State - 2026 Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('affa69e77ea49154', 'AR', '["state"]', 'election_dates', 'Is Governor Sarah Huckabee Sanders running for re-election in 2026?', '["Arkansas Governor election 2026","Who is defending the AR Governor seat?","Is Sarah Huckabee Sanders term limited?"]', 'Yes. Governor Sarah Huckabee Sanders (R) is defending her seat in the 2026 election, seeking her second term. Under the Arkansas Constitution, Governors are limited to two four-year terms, making her fully eligible for the 2026 ballot.', 'https://en.wikipedia.org/wiki/2026_Arkansas_elections', 'Wikipedia - 2026 Arkansas Elections', '2026-05-17', 'per_cycle', 'secondary_source', 'Statewide candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('6ee5f8b88e9d833e', 'AR', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Arkansas in 2026?', '["Is Tom Cotton up for re-election in 2026?","When is John Boozman''s next election?","Arkansas US Senate cycle 2026"]', 'The Class 2 U.S. Senate seat held by Tom Cotton (R) is up for election in 2026. Senator John Boozman (Class 3) was re-elected in 2022 and will not appear on the ballot again until 2028.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('d3a4af127ba45249', 'AR', '["federal"]', 'election_dates', 'How many U.S. House districts are in Arkansas for the 2026 election?', '["Arkansas congressional apportionment","Are all AR congressional seats up in 2026?","Number of US Representatives from Arkansas"]', 'Arkansas is apportioned 4 U.S. House districts. All four seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('e88abb5e2c3256b0', 'AR', '["state"]', 'election_dates', 'Which Arkansas State Legislature seats are up for election in 2026?', '["Are all Arkansas House seats up in 2026?","Arkansas Senate election cycle 2026","Which legislative districts are on the ballot in AR?"]', 'All 100 seats in the Arkansas House of Representatives (2-year terms) are up for election in 2026. The Arkansas State Senate has 35 members who serve staggered 4-year terms; approximately half (17 or 18 districts, depending on cohort) will be on the 2026 ballot.', 'https://www.arkleg.state.ar.us/', 'Arkansas State Legislature', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('3b1f9b09b929602a', 'AR', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Arkansas in 2026?', '["Is the Attorney General up in 2026?","AR statewide election list 2026","When is the next Secretary of State election in AR?"]', 'Arkansas elects its statewide executive officers on the midterm cycle. In 2026, the offices of Governor, Lieutenant Governor, Attorney General, Secretary of State, State Treasurer, State Auditor, and Commissioner of State Lands are all on the ballot.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('93ee5851e8b8ce27', 'AR', '["judicial"]', 'election_dates', 'When are Arkansas Supreme Court and judicial elections held?', '["Arkansas judicial elections 2026","Are AR judges elected?","Next nonpartisan judicial election Arkansas"]', 'Arkansas judges, including Supreme Court Justices, are elected in nonpartisan elections. Crucially, the nonpartisan general election for judicial candidates is held CONCURRENTLY with the preferential primary election on March 3, 2026. If no candidate wins a majority in March, a runoff is held during the November general election.', 'https://www.sos.arkansas.gov/uploads/elections/2026_Election_Calendar_Rev._6-2025_.pdf', 'Arkansas Secretary of State - 2026 Election Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('0d56ac7b434afa7b', 'AR', '["state"]', 'election_dates', 'What is the schedule for the Arkansas State Legislature sessions?', '["When does the AR legislature meet?","Arkansas fiscal vs regular legislative session","Is the Arkansas legislature full time?"]', 'The Arkansas General Assembly is part-time and meets annually but alternating in scope. In odd-numbered years, it convenes for a Regular Session on the second Monday in January. In even-numbered years (like 2026), it convenes for a Fiscal Session, which recent legislation shifted to begin on the second Wednesday in April.', 'https://www.5newsonline.com/article/news/local/new-law-moves-arkansas-primary-elections-may-march/527-30d83557-0517-4f87-b88e-fd81affbb823', 'Arkansas Act 405 (SB 353)', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('48e31b8c0d738d6a', 'AR', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Arkansas?', '["Age and residency for Arkansas Governor","Arkansas Constitution Article 6 Governor qualifications","Who is eligible to be Governor of Arkansas?"]', 'Under Article 6, Section 5 of the Arkansas Constitution, a candidate for Governor must be a citizen of the United States, at least 30 years of age, and must have resided within the state of Arkansas for at least seven years continuously preceding their election.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('9e51e8c1cf386521', 'AR', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for the Arkansas State Legislature?', '["Qualifications for AR State Representative","Age requirement Arkansas State Senate","Do I have to live in my district to run in AR?"]', 'Under Article 5 of the Arkansas Constitution, a candidate for the State Senate must be at least 25 years old. A candidate for the State House must be at least 21 years old. Both must be U.S. citizens, residents of Arkansas for at least two years, and residents of their specific district for at least one year prior to the election.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('45660e66bd09e389', 'AR', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Arkansas?', '["US Senate residency requirements Arkansas","Age to run for Congress in Arkansas","Federal constitutional requirements for AR candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('05e3ded467c013df', 'AR', '["state"]', 'candidate_eligibility', 'What are the term limits for the Arkansas State Legislature?', '["How many terms can an Arkansas state senator serve?","Are there term limits for the Arkansas House?","Arkansas Issue 2 term limit law 12 years"]', 'Arkansas enforces strict legislative term limits, recently updated by Issue 2 (2020). Legislators are currently limited to serving a maximum of 12 consecutive years in the General Assembly, in any combination of House and Senate service. Once the 12-year limit is reached, they must take a four-year break before becoming eligible to run again.', 'https://en.wikipedia.org/wiki/Arkansas_General_Assembly', 'Arkansas Constitution Amendment 100 (via Issue 2)', '2026-05-17', 'static', 'secondary_source', 'State legislative candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('f43052da091c9dd7', 'AR', '["state"]', 'candidate_eligibility', 'What are the term limits for the Arkansas Governor?', '["How many terms can an Arkansas Governor serve?","Sarah Huckabee Sanders term limits AR","Arkansas executive term limit law"]', 'Under Amendment 73 of the Arkansas Constitution, the Governor, Lieutenant Governor, Secretary of State, Treasurer, Auditor, and Attorney General are limited to serving two four-year terms in their respective offices.', 'https://ballotpedia.org/Governor_of_Arkansas', 'Arkansas Constitution Amendment 73', '2026-05-17', 'static', 'secondary_source', 'Statewide executive candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('c595ecdacaf97a28', 'AR', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Arkansas?', '["Arkansas county judge qualifications","Can I run for county board in AR?","County residency for AR officials"]', 'To run for a county office (such as County Judge, Sheriff, or Quorum Court Justice of the Peace), a candidate must generally be a qualified elector (registered voter) and a resident of the county or specific district they seek to represent at the time they assume office.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('783a1bd8e37d32a2', 'AR', '["state"]', 'candidate_eligibility', 'Does the Arkansas Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in AR","Do I need to be a member of the bar to be AR AG?","Legal requirements for Arkansas Attorney General"]', 'Yes. Statutory law requires the Attorney General of Arkansas to be a licensed attorney in good standing and admitted to practice before the Arkansas Supreme Court to fulfill their duties as the state''s chief legal officer.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('f5858dc779664019', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Arkansas?', '["Arkansas voter ID requirements","Do I need my driver''s license to vote in AR?","Acceptable ID for Arkansas voting"]', 'Yes. Arkansas has a strict photo ID requirement. Voters must present a valid document containing their photograph issued by the United States, the State of Arkansas, or an accredited postsecondary educational institution in Arkansas. If a voter fails to produce ID, they may cast a provisional ballot, but must return with an ID by the Monday following the election.', 'https://www.sos.arkansas.gov/elections/voter-information/voter-id-requirements', 'Arkansas Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('f6cced2d16952166', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Arkansas a universal mail ballot state?', '["Do all voters get a mail ballot in Arkansas?","Arkansas vote-by-mail system","Do I need an excuse to vote absentee in AR?"]', 'No. Arkansas is not a universal mail ballot state, and it does not allow no-excuse absentee voting. To vote by mail, a voter must submit an application certifying a valid excuse, such as being unavoidably absent from their polling site, illness, physical disability, or residing in a long-term care facility.', 'https://sbec.arkansas.gov/election-information/absentee-voting/', 'Arkansas Board of Election Commissioners', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('272889876837a6ef', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the timeline for early in-person voting in Arkansas?', '["Can I vote early in person in AR?","Arkansas early voting dates 2026","When does early voting start in Arkansas?"]', 'Arkansas offers 15 days of early in-person voting prior to an election. Early voting is available between 8:00 a.m. and 6:00 p.m., Monday through Friday, and 10:00 a.m. to 4:00 p.m. on Saturdays. It ends at 5:00 p.m. on the Monday immediately preceding Election Day.', 'https://www.sos.arkansas.gov/elections/voter-information/voter-registration-information/voting-in-arkansas', 'Arkansas Secretary of State - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('1525341d288a91c4', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Arkansas offer same-day registration?', '["Last day to register to vote in AR","Arkansas same day voter registration","Voter registration deadline 2026 Arkansas"]', 'The deadline to register to vote in Arkansas is 30 days prior to the election. Arkansas DOES NOT offer same-day voter registration. Residents must be registered in advance of the deadline to vote early or on Election Day.', 'https://www.sos.arkansas.gov/elections/voter-information', 'Arkansas Secretary of State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('6b6a54e6b40eecac', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Arkansas?', '["How close can I campaign to a polling place in AR?","Arkansas 100 feet electioneering rule","AR buffer zone around voting centers"]', 'Under Arkansas law, electioneering is strictly prohibited within 100 feet of the primary exterior entrance to any building where voting is taking place. This bans distributing campaign literature, displaying signs, and soliciting votes.', 'https://sbec.arkansas.gov/', 'Arkansas Board of Election Commissioners', '2026-05-17', 'static', 'official_source_direct', 'Campaign workers and Voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('0815506ec048ffbd', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Arkansas?', '["Can felons vote in Arkansas state?","Felony voting rights restoration AR","Voting on parole in Arkansas"]', 'In Arkansas, individuals convicted of a felony lose their voting rights. To have them restored, they must completely discharge their entire sentence, which includes completing all prison time, probation, and parole, AND paying all associated legal fees, fines, and restitution. Only upon full discharge can they re-register to vote.', 'https://www.sos.arkansas.gov/elections/voter-information', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('aed90e5212a38ff1', 'AR', '["county"]', 'voter_interaction', 'How many counties are in Arkansas, and why does it matter for campaigns?', '["Arkansas county election administration","How many county clerks in AR?","Local election control Arkansas"]', 'Arkansas has 75 counties. This operational footprint requires statewide campaigns to coordinate heavily with 75 distinct County Clerks and County Election Commissions, who directly administer polling places, process early voting, and tabulate paper ballots locally.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('0524136e9c3cc884', 'AR', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Arkansas?', '["Where do I file campaign finance reports in AR?","What is the Arkansas Ethics Commission?","Does the AR Secretary of State handle campaign finance?"]', 'Campaign finance and ethics laws in Arkansas are jointly administered. The Arkansas Secretary of State serves as the primary filing repository for financial disclosure reports, but the Arkansas Ethics Commission (AEC) enforces the laws, issues advisory opinions, and investigates violations.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('0d0290cb4ba614c4', 'AR', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Arkansas for the 2026 cycle?', '["Are there contribution limits in Arkansas?","AR individual donation caps 2026 election","Maximum donation to state legislature Arkansas"]', 'Arkansas DOES enforce contribution limits, indexed for inflation. Under Arkansas Code § 7-6-203, individuals may contribute up to $3,500 per election to a candidate for statewide or legislative office. Primary, primary runoff, general, and general runoff elections are all considered separate elections, allowing donors to give the limit multiple times.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Arkansas', 'Arkansas Ethics Commission / Ballotpedia', '2026-05-17', 'per_cycle', 'secondary_source', 'Candidates and Donors', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('16a476e639afaa67', 'AR', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Arkansas campaigns?', '["Corporate contribution ban Arkansas state","Can a business donate to my campaign in AR?","Corporate campaign finance rules Arkansas"]', 'No. Under Arkansas law, direct contributions from the treasury of a corporation or labor union to a candidate''s campaign committee are strictly PROHIBITED. Corporations may only make contributions through legally established and approved Political Action Committees (PACs), or give unlimited funds to ballot measure groups.', 'https://ballotpedia.org/Campaign_finance_requirements_in_Arkansas', 'Arkansas Campaign Finance Rules', '2026-05-17', 'static', 'secondary_source', 'Candidates and Businesses', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('6ae8fff16f9f2771', 'AR', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Arkansas?', '["AR PAC donation limits to candidates 2026","Political committee vs individual contribution limit Arkansas","Maximum PAC gift to state legislator AR"]', 'In Arkansas, approved Political Action Committees (PACs) are subject to the same contribution limits as individuals. A PAC is limited to contributing a maximum of $3,500 per election to a candidate for state or legislative office.', 'https://codes.findlaw.com/ar/title-7-elections/ar-code-sect-7-6-203/', 'Arkansas Code § 7-6-203', '2026-05-17', 'per_cycle', 'statute_citation', 'State candidates and PACs', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('732185553507cd79', 'AR', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Arkansas?', '["AR personal use prohibition campaign finance","Can I use campaign money for personal items in AR?","Prohibited expenditures Arkansas AEC"]', 'Yes. Under Arkansas Code § 7-6-203(f)(1), a candidate shall not take any campaign funds as personal income. Using campaign funds for personal enrichment is classified as a felony or misdemeanor depending on the financial amount converted.', 'https://codes.findlaw.com/ar/title-7-elections/ar-code-sect-7-6-203/', 'Arkansas Code § 7-6-203', '2026-05-17', 'static', 'statute_citation', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('8b33540e6826e279', 'AR', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Arkansas legislators?', '["Can Arkansas legislators raise money during session?","Lobbyist contribution ban AR legislature","Legislative session contribution rules Arkansas"]', 'Yes. Arkansas enforces a strict ''session freeze.'' State lawmakers, statewide elected officials, and the Governor are prohibited from accepting campaign contributions from any person during a regular legislative session, during any extended session, or during a special session. The freeze also applies to 30 days before and after a regular session.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('657ad0c08c629e0b', 'AR', '["state"]', 'finance_ethics', 'Does Arkansas provide public financing for state campaigns?', '["Public matching funds for Arkansas Governor","State funded campaigns Arkansas status","Government campaign grants AR"]', 'No. Arkansas does not have a system of public financing or matching funds for state-level political campaigns. Candidates must rely entirely on private contributions within the statutory limits set by the Arkansas Ethics Commission.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('324fc824c7a9c58a', 'AR', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Arkansas candidates?', '["AEC filing dates 2026","When are campaign finance reports due in AR?","Arkansas pre-primary and pre-general report deadlines"]', 'Candidates in Arkansas must file regular Contributions and Expenditure (C&E) Reports. In an election year, a candidate must file a pre-election report 7 days before any election, monthly reports for the months they raise over $500, and a final campaign report no later than 30 days after the election.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State - Candidate Filing', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('408bf0ea31cf63cb', 'AR', '["federal","state"]', 'redistricting', 'Who draws Arkansas congressional and legislative maps?', '["Does the AR legislature draw district maps?","Who has the authority to draw district lines in Arkansas?","Arkansas Board of Apportionment"]', 'Arkansas has a bifurcated redistricting process. The state legislature draws congressional district maps, which are subject to gubernatorial veto. However, state legislative districts are drawn by the Board of Apportionment, an executive-led body composed of the Governor, Secretary of State, and Attorney General.', 'https://ballotpedia.org/Redistricting_in_Arkansas', 'Ballotpedia - Redistricting in Arkansas', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('096d879eccd79604', 'AR', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Arkansas?', '["Standards for drawing Arkansas district lines","Arkansas gerrymandering rules","Board of Apportionment criteria AR"]', 'Under the Arkansas Constitution, state legislative districts must be contiguous, compact, and as nearly equal in population as practicable. Congressional districts must meet federal equal population standards. There are no state-level mandates prohibiting partisan gerrymandering.', 'https://ballotpedia.org/Redistricting_in_Arkansas', 'Arkansas Constitution Article 8', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('ffd84882908fa17e', 'AR', '["federal","state"]', 'redistricting', 'Are the current Arkansas redistricting maps operative for the 2026 cycle?', '["Status of 2021 Arkansas redistricting maps","Are there pending redistricting lawsuits in Arkansas?","Arkansas 2026 district boundaries"]', 'Yes. The congressional map enacted by the legislature in 2021 and the state legislative maps adopted by the Board of Apportionment in 2021 remain fully operative for the 2026 election cycle. Early litigation regarding partisan gerrymandering and the Voting Rights Act did not result in systemic map alterations.', 'https://ballotpedia.org/Redistricting_in_Arkansas', 'Ballotpedia - Redistricting in Arkansas', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('71ea0ad1cf7c0fcc', 'AR', '["state"]', 'redistricting', 'What is the Arkansas Board of Apportionment?', '["Arkansas executive redistricting commission","Who sits on the Board of Apportionment AR?","How are state legislative maps drawn in Arkansas?"]', 'The Board of Apportionment is a unique, three-member executive body tasked solely with drawing Arkansas state legislative districts. It is composed of the Governor, the Secretary of State, and the Attorney General.', 'https://arkansasag.gov/resources/board-of-apportionment/', 'Arkansas Attorney General - Board of Apportionment', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('eef8bf76fd2a8da7', 'AR', '["state"]', 'recall_rules', 'Does Arkansas have a recall mechanism for state officials?', '["Can the Governor of Arkansas be recalled?","How to recall a state senator in AR","Statewide recall election rules Arkansas"]', 'No. The State of Arkansas does not have any legal or constitutional mechanism for the recall of state-level elected officials, including the Governor or members of the state legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_Arkansas', 'Laws governing recall in Arkansas', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('25a197a36441ab24', 'AR', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Arkansas?', '["Arkansas county commissioner recall rules","Signature requirement local recall Arkansas","Recalling a mayor in AR"]', 'Arkansas law is highly restrictive regarding local recall. It is explicitly authorized ONLY for the mayor and directors in cities featuring a city manager form of government (requiring signatures equal to 35% of the votes cast for that office). It is not broadly available for most municipal or county officials.', 'https://ballotpedia.org/Laws_governing_recall_in_Arkansas', 'Laws governing recall in Arkansas', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('3e9d9b6bf34b83e9', 'AR', '["state"]', 'ballot_access', 'What is the signature threshold for a constitutional amendment by initiative in Arkansas?', '["How to amend the AR constitution by initiative","Arkansas citizen initiative signature requirements","Geographic distribution rule for AR constitutional initiatives"]', 'To qualify a constitutional amendment initiative, proponents must gather valid signatures equal to at least 10% of the total votes cast for Governor in the preceding election. Furthermore, signatures must meet a geographic distribution threshold: a minimum number of signatures from at least 50 of the state''s 75 counties.', 'https://www.sos.arkansas.gov/elections/initiatives-and-referenda', 'Arkansas Secretary of State - Initiatives', '2026-05-17', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('99952c05d717e901', 'AR', '["state"]', 'ballot_access', 'What is the signature threshold for a statutory initiative in Arkansas?', '["How to pass a state law by initiative in AR","Arkansas statutory initiative signature count","Difference between constitutional and statutory initiative Arkansas"]', 'To qualify a statutory (state law) initiative for the ballot, proponents must gather valid signatures equal to at least 8% of the total votes cast for Governor in the preceding election. Like constitutional amendments, they must also meet the geographic distribution requirement across 50 of 75 counties.', 'https://www.sos.arkansas.gov/elections/initiatives-and-referenda', 'Arkansas Secretary of State - Initiatives', '2026-05-17', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('130dcd50b77ac813', 'AR', '["state"]', 'ballot_access', 'What is the threshold and deadline for a veto referendum in Arkansas?', '["How to refer an AR bill to the ballot","Arkansas citizen referendum rules","Veto referendum signature threshold Arkansas state"]', 'Citizens can refer a passed legislative act to the ballot via a veto referendum. This requires signatures equal to 6% of the votes cast for Governor in the previous election, including the 50-county geographic distribution requirement. Signatures must be submitted within 90 days following the final adjournment of the legislative session.', 'https://www.sos.arkansas.gov/elections/initiatives-and-referenda', 'Arkansas Secretary of State - Initiatives', '2026-05-17', 'per_cycle', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('88d80d7061838ebd', 'AR', '["state"]', 'ballot_access', 'What are the legislatively referred ballot measures in Arkansas for 2026?', '["Arkansas 2026 constitutional amendments","What is on the Arkansas ballot in 2026?","Major ballot measures Arkansas 2026"]', 'The Arkansas legislature has referred four constitutional amendments to the 2026 general election ballot. These measures address: 1) Clarifying that only U.S. citizens may vote in elections; 2) Affirming the right to keep and bear arms; 3) Provisions regarding economic development districts; and 4) Regulations concerning municipal and county bond issuance.', 'https://ballotpedia.org/Arkansas_2026_ballot_measures', 'Ballotpedia - Arkansas 2026 Ballot Measures', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees and Strategists', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('0cd4557d5bb2b764', 'AR', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Arkansas?', '["Arkansas ballot measure pass threshold","Does a measure need a supermajority in AR?","Majority vote requirements Arkansas ballot measures"]', 'In Arkansas, all citizen initiatives (both statutory and constitutional) and legislatively referred constitutional amendments require only a simple majority (over 50%) of the total votes cast on that specific measure to pass.', 'https://www.sos.arkansas.gov/elections/initiatives-and-referenda', 'Arkansas Secretary of State - Initiatives', '2026-05-17', 'static', 'official_source_direct', 'Ballot measure committees', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('cbdafac91a159738', 'AR', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Arkansas?', '["Requirements to run for AR Secretary of State","Who can run for Secretary of State in AR?","Residency rules for Arkansas SOS"]', 'Under the Arkansas Constitution, a candidate for Secretary of State must be a citizen of the United States, at least 21 years old, and a resident of the state.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('ced88ea5494bb765', 'AR', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Arkansas?', '["Eligibility for Arkansas State Treasurer","Who can run for State Treasurer in AR?","Arkansas Treasurer residency requirements"]', 'Under the Arkansas Constitution, candidates for State Treasurer share the standard constitutional requirements for most executive officers: they must be a U.S. citizen, at least 21 years old, and a resident of Arkansas.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('16803beb10a3baef', 'AR', '["state"]', 'candidate_eligibility', 'What is the Commissioner of State Lands in Arkansas, and what are the qualifications?', '["What does the Commissioner of State Lands do?","Qualifications for Arkansas Land Commissioner","Is the Land Commissioner elected in AR?"]', 'The Commissioner of State Lands is a statewide elected constitutional officer in Arkansas primarily responsible for managing state-owned land, mineral rights, and handling tax-delinquent properties. Candidates must meet the standard executive qualifications: U.S. citizen, at least 21 years old, and a resident of the state.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State / Commissioner of State Lands', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('13eba21cc836a5b7', 'AR', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Arkansas?', '["Run for school board Arkansas requirements","Who can be a school board member in AR?","School board age rules Arkansas"]', 'To run for a local school board in Arkansas, a candidate must be a registered voter and a resident of the specific school district (and the specific election zone within the district, if applicable) they seek to represent.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State - Local Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('7493f9636b251e0c', 'AR', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Arkansas Supreme Court justices?', '["Arkansas Supreme Court Justice eligibility","Years of practice required for AR Supreme Court","Are Arkansas judges elected or appointed?"]', 'Arkansas Supreme Court Justices are elected in statewide nonpartisan elections. Candidates must be at least 30 years old, a citizen of the United States, a resident of Arkansas for at least two years preceding election, and a licensed attorney with at least eight years of active practice.', 'https://www.arcourts.gov/', 'Arkansas Judiciary', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('8144506b462674e8', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in Arkansas?', '["How to fix a rejected signature in AR","Arkansas ballot cure process deadline","Missing signature on AR mail ballot"]', 'Arkansas law does not currently provide a statutory signature cure process. If an absentee ballot return envelope is missing a signature or fails signature verification against the voter''s application/registration, the county election commission is generally authorized to reject the ballot without offering the voter an opportunity to cure the defect after Election Day.', 'https://sbec.arkansas.gov/election-information/absentee-voting/', 'Arkansas Board of Election Commissioners - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('2788d064451e995f', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Arkansas?', '["When are military ballots due in Arkansas?","UOCAVA return deadline AR","Overseas voting rules Arkansas state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Voted ballots returned by mail must be postmarked by Election Day and received no later than 10 days after the election to be counted.', 'https://www.sos.arkansas.gov/elections/voter-information/military-overseas-citizens', 'Arkansas Secretary of State - Military & Overseas', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('48ded6c57f0a5153', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Arkansas?', '["What is a provisional ballot in AR?","Voting without ID Arkansas","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued when a voter''s eligibility is in question (e.g., name not on roster) or if the voter fails to present a required government-issued photo ID. To have the ID-related provisional ballot counted, the voter must return to the county clerk or election commission with an acceptable photo ID by 12:00 noon on the Monday following the election.', 'https://www.sos.arkansas.gov/elections/voter-information/voter-id-requirements', 'Arkansas Secretary of State - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('060b70ab041ea17d', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Arkansas have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Arkansas DMV?","AR motor voter automatic registration","Do I have to register to vote if I get an AR driver''s license?"]', 'No. Arkansas does not have Automatic Voter Registration (AVR). While the Department of Finance and Administration (DFA) offers eligible citizens the opportunity to register to vote when applying for a license (compliance with federal Motor Voter laws), voters must actively opt-in to complete the registration process.', 'https://www.sos.arkansas.gov/elections/voter-information/voter-registration-information', 'Arkansas Secretary of State - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('5a12eeaecce60c39', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Arkansas offer Online Voter Registration?', '["Can I register to vote online in AR?","Arkansas electronic voter registration","AR SOS online registration portal"]', 'Yes. Eligible Arkansas residents with a valid state driver''s license or ID card can register to vote or update their registration securely using the Secretary of State''s online voter registration portal. The deadline is 30 days prior to the election.', 'https://www.sos.arkansas.gov/elections/voter-information/voter-registration-information', 'Arkansas Secretary of State - Online Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('c5a41a98c6933e80', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Arkansas maintain its voter registration lists?', '["AR voter list maintenance rules","How are inactive voters handled in Arkansas?","Arkansas voter roll cleaning process"]', 'The Secretary of State and county clerks conduct regular list maintenance utilizing the National Change of Address (NCOA) system and death records. If a voter is placed on the inactive list (e.g., mail is returned) and fails to vote or update their record over two consecutive federal general elections, their registration is canceled.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('f33a37e49bd1203c', 'AR', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Arkansas voter file?', '["Arkansas voter database access cost","How to get the voter list in AR","What data is included in the Arkansas voter file?"]', 'Campaigns and political committees can purchase the statewide voter registration list from the Secretary of State. The file includes voter names, addresses, and voting history, and requires submission of a request form and payment of an administrative fee. Its use is restricted to political and election-related purposes.', 'https://www.sos.arkansas.gov/elections/voter-information', 'Arkansas Secretary of State - Voter Information', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('d49fe19a1105535b', 'AR', '["federal","state","county"]', 'ballot_access', 'Does Arkansas have a sore loser law?', '["Can I run as an independent if I lose the AR primary?","Arkansas sore loser statute","General election ballot access after primary defeat AR"]', 'Yes. Arkansas enforces a sore loser law. A candidate who runs unsuccessfully for a political party''s nomination in the primary election is prohibited from subsequently running as an independent candidate for the same office in that year''s general election.', 'https://www.sos.arkansas.gov/elections/candidate-information', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Major party candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('6c42245cece3b095', 'AR', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Arkansas?', '["Does Arkansas use ranked choice voting?","RCV status in Arkansas 2026","Instant runoff voting AR"]', 'No. Ranked Choice Voting (RCV) is generally not used in Arkansas. The state relies on the traditional primary and general runoff system (requiring a 50%+1 majority) rather than utilizing instant runoff tabulations. However, overseas and military (UOCAVA) voters receive a ranked-choice absentee ballot for primary and general elections to ensure their votes can be tabulated in the event of a runoff election without needing to mail a second ballot.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('2e6fd0f3e413ae74', 'AR', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Arkansas campaign materials?', '["Arkansas ''Paid for by'' rules","Campaign ad disclaimer requirements AR","Political taglines Arkansas AEC"]', 'Arkansas campaign finance law requires that printed political materials and broadcast advertisements clearly indicate the individual or committee responsible for funding the communication. Disclaimers must prominently feature a ''Paid for by'' statement.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('4ad879cbd1a90454', 'AR', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Arkansas?', '["AR campaign coordination rules","When is a PAC expenditure not independent in Arkansas?","Prohibition on candidate-PAC coordination AR"]', 'An independent expenditure becomes ''coordinated'' (and thus is treated as an in-kind contribution subject to the $3,500 statutory limit) if the spending is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their authorized campaign committee.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('0e782abf490c8be6', 'AR', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Arkansas?', '["AR AEC late fee","Penalty for missing an Arkansas campaign finance deadline","Ethics Commission fine for late filing AR"]', 'The Arkansas Ethics Commission aggressively enforces reporting deadlines. A candidate or committee that files a report late is typically subject to a civil fine. Fines can reach $50 per day for the first 10 days, and up to $100 per day thereafter, depending on the severity and history of violations.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission - Rules', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('234a089320b8e2b0', 'AR', '["state","county","municipal"]', 'finance_ethics', 'When and how must an Arkansas campaign committee terminate?', '["Closing an Arkansas campaign committee","AEC committee termination requirements","Final campaign finance report Arkansas"]', 'A candidate committee may formally terminate when it has achieved a zero cash balance, legally disposed of all surplus funds, and resolved all outstanding debts or loans. A formal Final Report marking the campaign account as closed must be filed.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('ee1be6ed7f4e6560', 'AR', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Arkansas?', '["AR independent expenditure reporting AEC","Disclosure for AR independent expenditure groups","Reporting thresholds for outside spending Arkansas"]', 'Any person or committee making an independent expenditure exceeding $500 to expressly advocate for the election or defeat of a clearly identified candidate must file an independent expenditure report with the Secretary of State, maintaining transparency in outside spending. Due to recent changes, the report is due within 15 days of crossing the $500 threshold.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('45260ecc902d88c3', 'AR', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Arkansas?', '["Arkansas in-kind contribution valuation rules","Reporting non-monetary donations Arkansas campaign","Fair market value for in-kind gifts AR"]', 'In-kind contributions (donated goods, services, or equipment) must be reported at their reasonable fair market value. They count directly toward the donor''s per-election contribution limit ($3,500) and must be itemized if the value exceeds $50.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('80f2b8b857f712ce', 'AR', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Arkansas?', '["Arkansas candidate personal loan limits","Can I pay myself back for a campaign loan in AR?","Reporting candidate loans in AEC"]', 'A candidate may loan an unlimited amount of their own personal funds to their candidate committee; it is not subject to contribution limits. However, the loan must be formally executed and reported. Candidates may repay these personal loans from campaign contributions raised during the cycle.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('8774410ef5f0f106', 'AR', '["state","county","municipal"]', 'finance_ethics', 'What can Arkansas candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in AR?","AR surplus campaign funds rules","Donating remaining campaign funds Arkansas"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign, return them pro-rata to contributors, donate them to an organized political party, or donate them to an IRS-recognized charitable organization.', 'https://arkansasethics.com/', 'Arkansas Ethics Commission', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('93e1af6ed230157f', 'AR', '["state","county","municipal"]', 'finance_ethics', 'What are Arkansas''s rapid disclosure requirements for large contributions?', '["Arkansas 72-hour large contribution report","Late contribution reporting Arkansas AEC","When do I file a rapid report in AR?"]', 'Arkansas campaign finance law requires rapid reporting prior to elections. Any contribution of $500 or more received in the days immediately preceding an election must be reported within 48 to 72 hours of receipt depending on the specific reporting schedule calendar provided by the AEC.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State - Reporting Calendar', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('66e2dd043359fc2d', 'AR', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Arkansas?', '["When are county sheriffs elected in AR?","Arkansas county official term lengths","Are county assessors on the 2026 ballot?"]', 'Elected county officials in Arkansas—including County Judges, Sheriffs, Assessors, and Quorum Court members—typically serve four-year or two-year terms depending on the office. Because Quorum Court Justices of the Peace serve two-year terms, they are heavily featured on the 2026 midterm ballot.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('5c780993943a464c', 'AR', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Arkansas elections?', '["When are Arkansas election results official?","AR certification deadline","State Board of Election Commissioners meeting Arkansas"]', 'County election commissions must meet to officially certify local results no later than 15 days following the election. Following this, the Secretary of State compiles the results, and the State Board of Election Commissioners typically certifies statewide and federal election returns shortly thereafter.', 'https://sbec.arkansas.gov/', 'Arkansas Board of Election Commissioners', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T16-24-02_arkansas_full_v1'),
  ('30cc2a39d2a90805', 'AR', '["federal","state"]', 'election_dates', 'When and how are special elections called in Arkansas?', '["Arkansas special election timeline","Who calls a special election to fill a US House vacancy in AR?","Filling a midterm vacancy Arkansas"]', 'Special elections to fill federal or state legislative vacancies are called by a proclamation from the Governor. Under state law, special elections are generally scheduled on specific consolidated dates (such as the second Tuesday in February, May, or August, or the November general date) to manage administrative efficiency.', 'https://www.sos.arkansas.gov/elections', 'Arkansas Secretary of State', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T16-24-02_arkansas_full_v1')
